import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.StringReader;
import java.security.Principal;
import java.util.HashMap;
import java.util.Map;

import org.w3c.dom.Document;
import org.w3c.dom.Element;

public class SAMLResponseProcessor {

    public Principal authenticate(String samlResponse) throws Exception {
        // Parse SAML response XML
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        DocumentBuilder db = dbf.newDocumentBuilder();
        Document samlResponseDoc = db.parse(new StringReader(samlResponse));

        // Check for Response element
        Element responseElement = samlResponseDoc.getDocumentElement();
        if (!responseElement.getLocalName().equals("Response")) {
            throw new Exception("Invalid SAML response");
        }

        // Extract assertions and user attributes
        Map<String, String> attributes = new HashMap<>();
        for (Element assertion : (Element[]) samlResponseDoc.getElementsByTagName("Assertion")) {
            for (Element attribute : (Element[]) assertion.getElementsByTagName("Attribute")) {
                attributes.put(attribute.getAttribute("Name"), attribute.getTextContent());
            }
        }

        // Create authenticated session based on assertion content
        return new Principal() {
            @Override
            public String getName() {
                return attributes.get("username");
            }
        };
    }
}